26	void riscv_nn_relu_s8(q7_t * in_out, uint32_t size)
27	{
28	#ifdef ENA_EMPTY_FUN
29	    //empty body
30	#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
31	    unsigned long dlen_ratio = NDS_VEC_CSR_GET_DLEN_RATIO();
32	    long vl, maxvl_perf_vg;
33	    long size2 = size;
34	    if (dlen_ratio == NDS_MVEC_CFG_DW_VAL_1_1)
35	    {
36	        maxvl_perf_vg = __riscv_vsetvlmax_e8m8();
37	        long maxvl_per_loop = maxvl_perf_vg << 2;
38	        while (size2 >= maxvl_per_loop)
39	        {
40	            q7_t * in_out2 = in_out + maxvl_perf_vg;
41	            vint8m8_t vIn_out = __riscv_vle8_v_i8m8(in_out, maxvl_perf_vg);
42	            q7_t * in_out3 = in_out2 + maxvl_perf_vg;
43	            vint8m8_t vIn_out2 = __riscv_vle8_v_i8m8(in_out2, maxvl_perf_vg);
44	            q7_t * in_out4 = in_out3 + maxvl_perf_vg;
45	            vint8m8_t vIn_out3 = __riscv_vle8_v_i8m8(in_out3, maxvl_perf_vg);
46	            vint8m8_t vIn_out4 = __riscv_vle8_v_i8m8(in_out4, maxvl_perf_vg);
47	            vIn_out = __riscv_vmax(vIn_out, 0, maxvl_perf_vg);
48	            vIn_out2 = __riscv_vmax(vIn_out2, 0, maxvl_perf_vg);
49	            vIn_out3 = __riscv_vmax(vIn_out3, 0, maxvl_perf_vg);
50	            vIn_out4 = __riscv_vmax(vIn_out4, 0, maxvl_perf_vg);
51	            __riscv_vse8(in_out, vIn_out, maxvl_perf_vg);
52	            in_out += maxvl_per_loop;
53	            __riscv_vse8(in_out2, vIn_out2, maxvl_perf_vg);
54	            size2 -= maxvl_per_loop;
55	            __riscv_vse8(in_out3, vIn_out3, maxvl_perf_vg);
56	            __riscv_vse8(in_out4, vIn_out4, maxvl_perf_vg);
57	        }
58	
59	        while (size2 > 0)
60	        {
61	            vl = __riscv_vsetvl_e8m8(size2);
62	            vint8m8_t vIn_out = __riscv_vle8_v_i8m8(in_out, vl);
63	            size2 -= vl;
64	            vIn_out = __riscv_vmax(vIn_out, 0, vl);
65	            __riscv_vse8(in_out, vIn_out, vl);
66	            in_out += vl;
67	        }
68	    }
69	    else
70	    {
71	        maxvl_perf_vg = __riscv_vsetvlmax_e8m4();
72	        long maxvl_per_loop = maxvl_perf_vg << 2;
73	        while (size2 >= maxvl_per_loop)
74	        {
75	            q7_t * in_out2 = in_out + maxvl_perf_vg;
76	            vint8m4_t vIn_out = __riscv_vle8_v_i8m4(in_out, maxvl_perf_vg);
77	            q7_t * in_out3 = in_out2 + maxvl_perf_vg;
78	            vint8m4_t vIn_out2 = __riscv_vle8_v_i8m4(in_out2, maxvl_perf_vg);
79	            q7_t * in_out4 = in_out3 + maxvl_perf_vg;
80	            vint8m4_t vIn_out3 = __riscv_vle8_v_i8m4(in_out3, maxvl_perf_vg);
81	            vint8m4_t vIn_out4 = __riscv_vle8_v_i8m4(in_out4, maxvl_perf_vg);
82	            vIn_out = __riscv_vmax(vIn_out, 0, maxvl_perf_vg);
83	            vIn_out2 = __riscv_vmax(vIn_out2, 0, maxvl_perf_vg);
84	            vIn_out3 = __riscv_vmax(vIn_out3, 0, maxvl_perf_vg);
85	            vIn_out4 = __riscv_vmax(vIn_out4, 0, maxvl_perf_vg);
86	            __riscv_vse8(in_out, vIn_out, maxvl_perf_vg);
87	            in_out += maxvl_per_loop;
88	            __riscv_vse8(in_out2, vIn_out2, maxvl_perf_vg);
89	            size2 -= maxvl_per_loop;
90	            __riscv_vse8(in_out3, vIn_out3, maxvl_perf_vg);
91	            __riscv_vse8(in_out4, vIn_out4, maxvl_perf_vg);
92	        }
93	
94	        while (size2 > 0)
95	        {
96	            vl = __riscv_vsetvl_e8m4(size2);
97	            vint8m4_t vIn_out = __riscv_vle8_v_i8m4(in_out, vl);
98	            size2 -= vl;
99	            vIn_out = __riscv_vmax(vIn_out, 0, vl);
100	            __riscv_vse8(in_out, vIn_out, vl);
101	            in_out += vl;
102	        }
103	    }
104	#elif defined(ENA_VEC_ISA)
105	    unsigned long dlen_ratio = NDS_VEC_CSR_GET_DLEN_RATIO();
106	    unsigned long my_vtype;
107	    if (dlen_ratio == NDS_MVEC_CFG_DW_VAL_1_1)
108	    {
109	        my_vtype = NDS_VEC_MAKE_VTYPE(NDS_VEC_VTYPE_SEW_VAL_E8, NDS_VEC_VTYPE_LMUL_VAL_M8);
110	    }
111	    else
112	    {
113	        my_vtype = NDS_VEC_MAKE_VTYPE(NDS_VEC_VTYPE_SEW_VAL_E8, NDS_VEC_VTYPE_LMUL_VAL_M4);
114	    }
115	
116	    long vl, maxvl_perf_vg;
117	    long size2 = size;
118	
119	    NDS_VEC_VSETVL(maxvl_perf_vg, reg_x0, my_vtype);
120	    long maxvl_per_loop = maxvl_perf_vg << 2;
121	    while (size2 >= maxvl_per_loop)
122	    {
123	        q7_t * in_out2 = in_out  + maxvl_perf_vg;
124	        NDS_VEC_VLE8_V(NDS_VEC_V0, in_out);
125	        q7_t * in_out3 = in_out2 + maxvl_perf_vg;
126	        NDS_VEC_VLE8_V(NDS_VEC_V8, in_out2);
127	        q7_t * in_out4 = in_out3 + maxvl_perf_vg;
128	        NDS_VEC_VLE8_V(NDS_VEC_V16, in_out3);
129	        NDS_VEC_VLE8_V(NDS_VEC_V24, in_out4);
130	        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
131	        NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, 0);
132	        NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0);
133	        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, 0);
134	        NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
135	        in_out += maxvl_per_loop;
136	        NDS_VEC_VSE8_V(NDS_VEC_V8, in_out2);
137	        size2 -= maxvl_per_loop;
138	        NDS_VEC_VSE8_V(NDS_VEC_V16, in_out3);
139	        NDS_VEC_VSE8_V(NDS_VEC_V24, in_out4);
140	    }
141	
142	    while (size2 > 0)
143	    {
144	        NDS_VEC_VSETVL(vl, size2, my_vtype);
145	        NDS_VEC_VLE8_V(NDS_VEC_V0, in_out);
146	        size2 -= vl;
147	        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
148	        NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
149	        in_out += vl;
150	    }
151	#elif defined(ENA_DSP_ISA)
152	    long_t cst_zero = 0L;
153	
154	    while (size >= (SIMD_NUM_Q7*2))
155	    {
156	        suni_t in_q7_1 = simd_load_8(in_out, 0);
157	        in_q7_1.l0 = NDS_DSP_SMAX8(in_q7_1.l0, cst_zero);
158	        simd_save_8(in_out, in_q7_1.l0);
159	        in_out += SIMD_NUM_Q7;
160	        size -= SIMD_NUM_Q7;
161	
162	        suni_t in_q7_2 = simd_load_8(in_out, 0);
163	        in_q7_2.l0 = NDS_DSP_SMAX8(in_q7_2.l0, cst_zero);
164	        simd_save_8(in_out, in_q7_2.l0);
165	        in_out += SIMD_NUM_Q7;
166	        size -= SIMD_NUM_Q7;
167	    }
168	
169	    while (size > 0)
170	    {
171	        *in_out = NDS_DSP_CLIP(*in_out, 8);
172	        in_out++;
173	        size--;
174	    }
175	#else
176	    uint32_t  i;
177	
178	    for (i = 0; i < size; i++)
179	    {
180	        if (in_out[i] < 0)
181	            in_out[i] = 0;
182	    }
183	
184	#endif
185	
186	}
